    @objc dynamic public class func drawPin(frame targetFrame: CGRect = CGRect(x: 0, y: 0, width: 100, height: 127), resizing: ResizingBehavior = .aspectFit) {
        //// General Declarations
        let context = UIGraphicsGetCurrentContext()!
        
        //// Resize to Target Frame
        context.saveGState()
        let resizedFrame: CGRect = resizing.apply(rect: CGRect(x: 0, y: 0, width: 100, height: 127), target: targetFrame)
        context.translateBy(x: resizedFrame.minX, y: resizedFrame.minY)
        context.scaleBy(x: resizedFrame.width / 100, y: resizedFrame.height / 127)
        let resizedShadowScale: CGFloat = min(resizedFrame.width / 100, resizedFrame.height / 127)



        //// Shadow Declarations
        let shadow = NSShadow()
        shadow.shadowColor = UIColor.black.withAlphaComponent(0.5)
        shadow.shadowOffset = CGSize(width: 9, height: 12)
        shadow.shadowBlurRadius = 16

        //// Oval Drawing
        let ovalPath = UIBezierPath()
        ovalPath.move(to: CGPoint(x: 97.5, y: 53.1))
        ovalPath.addCurve(to: CGPoint(x: 50, y: 122), controlPoint1: CGPoint(x: 97.5, y: 79.11), controlPoint2: CGPoint(x: 50, y: 122))
        ovalPath.addCurve(to: CGPoint(x: 3, y: 53.1), controlPoint1: CGPoint(x: 50, y: 122), controlPoint2: CGPoint(x: 3, y: 79.11))
        ovalPath.addCurve(to: CGPoint(x: 50.25, y: 6), controlPoint1: CGPoint(x: 3, y: 27.09), controlPoint2: CGPoint(x: 24.15, y: 6))
        ovalPath.addCurve(to: CGPoint(x: 97.5, y: 53.1), controlPoint1: CGPoint(x: 76.35, y: 6), controlPoint2: CGPoint(x: 97.5, y: 27.09))
        ovalPath.close()
        context.saveGState()
        context.setShadow(offset: CGSize(width: shadow.shadowOffset.width * resizedShadowScale, height: shadow.shadowOffset.height * resizedShadowScale), blur: shadow.shadowBlurRadius * resizedShadowScale, color: (shadow.shadowColor as! UIColor).cgColor)
        UIColor.blue.setFill()
        ovalPath.fill()
        context.restoreGState()
        
        context.restoreGState()

    }

